-- Add group-management fields to the quinielas table and enforce uniqueness
-- on quiniela names across the entire system.
--
-- invite_code is a short, human-friendly token (10 chars from an unambiguous
-- alphabet) generated by the application layer when a quiniela is created.
-- It is stored in the database as the join mechanism: users share the code
-- out-of-band (WhatsApp, SMS) and the API resolves it to the quiniela.
--
-- entry_fee and currency support future payment-tracking workflows. They are
-- nullable-free (NOT NULL DEFAULT) so queries never need to handle NULL
-- arithmetic when summing fees.
--
-- max_members is nullable: NULL means the group has no size cap, which is the
-- default for most casual quinielas. A non-null value enforces an upper bound
-- enforced at the service layer before inserting a membership row.

ALTER TABLE quinielas
    ADD COLUMN invite_code VARCHAR(12)  NOT NULL DEFAULT '',
    ADD COLUMN entry_fee   INTEGER      NOT NULL DEFAULT 0,
    ADD COLUMN currency    VARCHAR(3)   NOT NULL DEFAULT 'MXN',
    ADD COLUMN max_members INTEGER;

-- Backfill invite_code for any pre-existing rows (dev/test data).
-- In production this migration runs on an empty table, but the UPDATE
-- keeps the constraint satisfiable during the migration transaction.
UPDATE quinielas
SET invite_code = UPPER(SUBSTRING(MD5(RANDOM()::TEXT), 1, 10))
WHERE invite_code = '';

ALTER TABLE quinielas
    ADD CONSTRAINT quinielas_invite_code_key UNIQUE (invite_code),
    ADD CONSTRAINT quinielas_name_key        UNIQUE (name);
